    public partial class HelpTopicService : BaseService<HelpTopic>, IHelpTopicService
    {
        public HelpTopicService(IUnitOfWork uow) : base(uow)
        {

        }

        public override async Task Validation(HelpTopic item, Result<HelpTopic> executionResult)
        {
            if (await UOW.GetRepositoryAsync<HelpTopic>().HasRecordsAsync(x => x.Name == item.Name && x.Status == true && x.ID != item.ID))
            {
                executionResult.AddMessageItem(new MessageItem(nameof(HelpTopic.Name), "Name already exists"));
            }
        }
        public override async Task<HelpTopic> GetById(Guid id)
        {
            return await UOW.GetRepositoryAsync<HelpTopic>().SingleAsync(
                predicate: x => x.ID == id,
                include: i => i.Include(x => x.Department).Include(x => x.TicketStatus),
                orderBy: o => o.OrderByDescending(x => x.AddedAt));
        }

        public override async Task<IEnumerable<HelpTopic>> GetList(string orderBy)
        {
            return await UOW.GetRepositoryAsync<HelpTopic>().GetListAsync(orderBy, x => x.Status == true);
        }

        public override async Task<IPaginate<HelpTopic>> GetPaginate(BaseSearch search)
        {
            return await UOW.GetRepositoryAsync<HelpTopic>().GetPageListAsync(
                predicate: x => (string.IsNullOrEmpty(search.Name)
                     || x.Name.Contains(search.Name)
                     || x.Department.Department.Contains(search.Name)
                     || x.TicketStatus.Name.Contains(search.Name)),
                include: i => i.Include(x => x.Department).Include(x => x.TicketStatus),
                index: search.Page, size: search.Size, sortBy: search.SortBy ?? "Name", ascending: !search.IsDescend);
        }
    }
